const msg = $input.first().json.message;
const text = (msg?.text || '').trim();
const chatId = msg?.chat?.id;
const userId = String(msg?.from?.id || '');
const firstName = msg?.from?.first_name || 'друг';

let command = 'text';
if (text.startsWith('/start'))    command = 'start';
else if (text.startsWith('/help')) command = 'help';
else if (text.startsWith('/bewerben') || text.startsWith('/bewerbung')) command = 'bewerben';
else if (text.startsWith('/status'))  command = 'status';
else if (text.startsWith('/'))         command = 'unknown_cmd';

return [{ json: { chatId, userId, firstName, text, command, rawMessage: msg } }];

const response = $input.first().json;
const anschreiben = response.content?.[0]?.text || 'Не удалось сгенерировать. Попробуй ещё раз через /bewerben';
const chatId = $('Parse Message').first().json.chatId;
const firstName = $('Parse Message').first().json.firstName;

// Trim and clean up
const cleaned = anschreiben.trim();

return [{ json: { chatId, firstName, anschreiben: cleaned } }];
